import React, { useState, useEffect } from "react";
import "./Style.css";

import imgE1 from "./img/empresas/1.jpg";
import imgE2 from "./img/empresas/2.jpg";
import imgE3 from "./img/empresas/3.jpg";
import imgE4 from "./img/empresas/4.jpg";
import imgE5 from "./img/empresas/5.jpg";
import imgE6 from "./img/empresas/6.jpg";

import imgP1 from "./img/4.png";
import imgP2 from "./img/1.png";
import imgP3 from "./img/3.png";
import imgP4 from "./img/2.png";
import imgP5 from "./img/5.png";

import imgParceiro from "./img/imagemPet.png";

import Incen1 from "./img/Incentivadores/1.png";
import Incen2 from "./img/Incentivadores/2.png";
import Incen3 from "./img/Incentivadores/3.png";
import Incen4 from "./img/Incentivadores/4.png";
import Incen5 from "./img/Incentivadores/5.png";
import Incen6 from "./img/Incentivadores/6.png";
import Incen7 from "./img/Incentivadores/7.png";
import Incen8 from "./img/Incentivadores/8.png";
import Incen9 from "./img/Incentivadores/9.png";
import Incen10 from "./img/Incentivadores/10.png";
import Incen11 from "./img/Incentivadores/11.png";
import Incen12 from "./img/Incentivadores/OngCaramelo.png";


function Empresas() {
  const images = [imgP1, imgP2, imgP3, imgP4, imgP5];
  const [index, setIndex] = useState(0);

  // Função para trocar o slide manualmente
  const moveSlide = (step) => {
    setIndex((prev) => (prev + step + images.length) % images.length);
  };

  // AUTOPLAY: troca a imagem a cada 4.5 segundos
  useEffect(() => {
    const interval = setInterval(() => {
      setIndex((prev) => (prev + 1) % images.length);
    }, 4500);

    return () => clearInterval(interval);
  }, [images.length]);

  return (
    <section className="empresas-section">
      {/* Carrossel */}
      <div className="carousel-wrapper">
        <button className="btn prev" onClick={() => moveSlide(-1)}>
          &#10094;
        </button>

        <div className="carousel">
          <div
            className="carousel-track"
            style={{ transform: `translateX(-${index * 100}%)` }}
          >
            {images.map((src, i) => (
              <div className="carousel-item" key={i}>
                <img src={src} alt={`slide-${i}`} />
              </div>
            ))}
          </div>
        </div>

        <button className="btn next" onClick={() => moveSlide(1)}>
          &#10095;
        </button>
      </div>

      <div className="empresas-container">

          <h2 className="titulo-principal">Patrocinadores</h2>
          <p>Essas marcas acreditam na nossa causa e são fundamentais para manter o <b>Patas do amanha</b> funcionando todos os dias. Graças às doações delas, <b>oferecemos estrutura de qualidade e todo o cuidado</b> que nossos resgatados precisam para recomeçar.</p>


          {/* Empresas */}
          <article className="bloco-apoiadores">
            <h4 className="titulo-lista">As empresas que apoiam nossa causa</h4>
            <div className="galeria apoiadores-empresas">
              <figure>
                <img src={imgE1} alt="Logo Vision Motors" />
                <figcaption>PetShopping: cuidado completo para pets, com banho, tosas e muito carinho.</figcaption>
              </figure>
              <figure>
                <img src={imgE2} alt="Logo Aurora Tech" />
                <figcaption>Construções Pet: criando e reformando lares confortáveis para todos os pets.</figcaption>
              </figure>
              <figure>
